import base64
from pathlib import Path


HUAWEI_LOGO_SVG = """

<div style="display:flex; align-items:center; gap:16px;">
  <img src="data:image/png;base64," style="height:24px;">
  <div style="width:1px; height:24px; background:rgba(255,255,255,0.2);"></div>
  <span style="font-family:'Rostex', sans-serif; font-size:24px; color:#fff; letter-spacing:1px; line-height:1; position:relative; top:2px;">Tech4Connect</span>
</div>

"""


_STATIC_DIR = Path(__file__).resolve().parent / "static"


def _font_face(family: str, weight: int, filename: str) -> str:
    font_path = _STATIC_DIR / filename
    if not font_path.exists():
        return ""
    encoded = base64.b64encode(font_path.read_bytes()).decode("ascii")
    return (
        "@font-face {"
        f"font-family:'{family}';"
        f"src:url(data:font/ttf;base64,{encoded}) format('truetype');"
        f"font-weight:{weight};"
        "font-display:swap;"
        "}"
    )


_FONT_CSS = "\n".join(
    [
        _font_face("HuaweiSans", 100, "HuaweiSans-Thin.ttf"),
        _font_face("HuaweiSans", 300, "HuaweiSans-Light.ttf"),
        _font_face("HuaweiSans", 400, "HuaweiSans-Regular.ttf"),
        _font_face("HuaweiSans", 500, "HuaweiSans-Medium.ttf"),
        _font_face("HuaweiSans", 700, "HuaweiSans-Bold.ttf"),
        _font_face("Rostex", 400, "rostex.regular.ttf"),
    ]
)


